from flask import Flask, request, jsonify, redirect, url_for
import secrets
from itsdangerous import URLSafeTimedSerializer

app = Flask(__name__)
app.secret_key = 'supersecretkey'
reset_serializer = URLSafeTimedSerializer(app.secret_key)

# Simulated database
users = {}

def send_email(to_email, link):
    # Placeholder function to mimic sending an email
    print(f'Sent to {to_email}: {link}')

@app.route('/enable-mfa/<email>', methods=['POST'])
def enable_mfa(email):
    user = users.get(email)
    if user:
        user['mfa_enabled'] = True
        return jsonify({"message": "MFA enabled."}), 200
    return jsonify({"message": "User not found."}), 404

@app.route('/disable-mfa/<email>', methods=['POST'])
def disable_mfa(email):
    user = users.get(email)
    if user:
        user['mfa_enabled'] = False
        return jsonify({"message": "MFA disabled."}), 200
    return jsonify({"message": "User not found."}), 404

@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    data = request.json
    email = data.get('email')
    user = users.get(email)
    if user:
        token = reset_serializer.dumps(email, salt='reset-mfa')
        reset_link = url_for('reset_mfa_confirm', token=token, _external=True)
        send_email(email, reset_link)
        return jsonify({"message": "Reset link sent to email."}), 200
    return jsonify({"message": "User not found."}), 404

@app.route('/reset-mfa-confirm/<token>', methods=['GET'])
def reset_mfa_confirm(token):
    try:
        email = reset_serializer.loads(token, salt='reset-mfa', max_age=3600)
    except Exception:
        return jsonify({"message": "Invalid or expired token."}), 400

    user = users.get(email)
    if user:
        user['mfa_enabled'] = False
        return jsonify({"message": "MFA reset, you can now log in with your password."}), 200
    return jsonify({"message": "User not found."}), 404

# Example route for registration to populate users
@app.route('/register', methods=['POST'])
def register():
    data = request.json
    email = data.get('email')
    if email in users:
        return jsonify({"message": "User already exists."}), 400
    users[email] = {"mfa_enabled": False}
    return jsonify({"message": "User registered."}), 201

